async (page) => {
  // Navigate toward Forester at (216, 114)
  const r1 = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 216, y: 114});
  await page.waitForTimeout(4000);
  const pos = await page.evaluate(() => window.__latestGameState ? window.__latestGameState.player_position : null);

  const nearby = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return gs ? gs.nearby_entities.filter(e => e.type === 1).slice(0, 5) : [];
  });

  return JSON.stringify({pos, nearby});
}

async (page) => {
  // Click Forester to walk adjacent
